using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public sealed class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    [ColumnName("Label")]
    public bool Churned { get; set; }
}

public sealed class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedChurned { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public sealed class ChurnModelService
{
    private readonly MLContext _mlContext = new(seed: 42);
    private ITransformer? _model;

    public string TrainAndEvaluate(string dataPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<CustomerData>(
            dataPath, hasHeader: true, separatorChar: ',');

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Map "Yes"/"No" to true/false, encode Region, combine features
        var pipeline = _mlContext.Transforms.CustomMapping<RawLabel, MappedLabel>(
                (input, output) => output.Label = input.Label,
                contractName: null)
            .Append(_mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
            .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        _model = pipeline.Fit(split.TrainSet);

        var predictions = _model.Transform(split.TestSet);
        var metrics = _mlContext.BinaryClassification.Evaluate(predictions);

        return $"Accuracy: {metrics.Accuracy:F4}, AUC: {metrics.AreaUnderRocCurve:F4}, F1: {metrics.F1Score:F4}";
    }

    public ITransformer GetModel() =>
        _model ?? throw new InvalidOperationException("Model has not been trained. Call TrainAndEvaluate first.");

    public MLContext GetMlContext() => _mlContext;

    // These types let ML.NET load the CSV's "Yes"/"No" Label as a bool via CustomMapping
    private sealed class RawLabel
    {
        [Microsoft.ML.Data.ColumnName("Label")]
        public bool Label { get; set; }
    }

    private sealed class MappedLabel
    {
        [Microsoft.ML.Data.ColumnName("Label")]
        public bool Label { get; set; }
    }
}

