using Microsoft.Extensions.ML;
using Microsoft.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

var modelService = new ChurnModelService();
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var metrics = modelService.TrainAndEvaluate(dataPath);
Console.WriteLine($"Model trained. {metrics}");

// Save model to a temp file for PredictionEnginePool
var modelPath = Path.Combine(Path.GetTempPath(), "churn_model.zip");
modelService.GetMlContext().Model.Save(modelService.GetModel(), null, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => $"Churn Predictor API is running. {metrics}");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerPredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
        Churned = string.Empty
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.PredictedChurned,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

public sealed record CustomerPredictRequest(float Age, float Income, string Region, float PurchaseHistory);

