using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public sealed class ChurnModelService
{
    private readonly MLContext _mlContext = new(seed: 42);
    private ITransformer? _model;

    public string TrainAndEvaluate(string dataPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<CustomerData>(
            dataPath, hasHeader: true, separatorChar: ',');

        var pipeline = _mlContext.Transforms.Conversion.MapValue(
                "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false }, "Churned")
            .Append(_mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
            .Append(_mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        long rowCount = data.GetColumn<float>("Age").LongCount();

        // Use train/test split only when the dataset is large enough
        if (rowCount >= 20)
        {
            var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
            _model = pipeline.Fit(split.TrainSet);

            var predictions = _model.Transform(split.TestSet);
            var metrics = _mlContext.BinaryClassification.Evaluate(predictions);
